package com.example.LifeAudit1;

import jakarta.transaction.Transactional;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/lifeaudit")
public class LifeAuditController {

    private final LService service;
    public LifeAuditController(LService service) {
        this.service = service;
    }


    @PostMapping()
    public LifeModel getdata(@RequestParam String Name , @RequestParam  Integer Age,@RequestParam Integer Hours_Worked ,@RequestParam  Float SleepHours ,@RequestParam Integer StressLevel ){
        LifeModel obj = new LifeModel(Name,Age,Hours_Worked,SleepHours,StressLevel);
        service.add(obj);
        return obj;
    }

    @Transactional
    @DeleteMapping("/{name}")
    public void del(@PathVariable String name){
service.deleteName(name);
}
    @GetMapping("/{Name}")
    public String showdata(@PathVariable String Name){
        LifeModel data = service.getName(Name);
        int age=data.getAge();
        float sh=data.getSh();
        int Hrw = data.getHrw();
        int Sl=data.getSl();

        String result;

        if (Hrw <8 && sh > 7) {
            //result = Name + ", stressed without working much. Legendary combo.";
            result = "<html>"+ "<h1> "+ Name+ " this stress at this age? Relax, life hasn’t started.</h1>"+"</html>"+"<img src =data:image/jpeg;base64,  >";
        }
        else if (sh< 6) {
            result = "<html> <h1> "+Name + ", sleep is important. Zombies don’t get promotions. </h1> <img src https://img.freepik.com/free-vector/creepy-green-zombie-cartoon-style_1308-132426.jpg?semt=ais_hybrid&w=740&q=80> </html>";
        }
        else if (Hrw >= 8 && sh > 7) {
            result = "<h1>" + Name + ", working hard and still stressed. Capitalism wins.</h1>";
        }
        else if (age < 25 && Sl>8) {
            result = "<html> <h1>"+Name + "this stress at this age? Relax, life hasn’t started.</h1> </html>";
        }
        else {
            result = Name + ", doing okay. Suspiciously balanced.";
        }

        return result;

    }
}
